/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    let totalSumX = 0;
    const n = nums.length;

    if (n <= 1) {
        return 0;
    }

    // We need nums[i] <= nums[i+1] for all i.
    // If nums[i] > nums[i+1], we must increase nums[i+1] by at least nums[i] - nums[i+1]
    // relative to nums[i], or decrease nums[i] relative to nums[i+1].
    // Since we can only increase elements, we must increase nums[i+1] or beyond.
    // The key insight here is to look at the required difference at each adjacent pair.

    // Consider the difference d_i = nums[i] - nums[i+1].
    // If d_i > 0, we need to bridge this gap by adding at least d_i to nums[i+1] or to elements to its right.
    // If we apply an operation with value x to a subarray starting at index k >= i+1, it increases nums[i+1].
    // If we apply an operation with value x to a subarray ending at index j <= i, it increases nums[i].

    // The problem asks for the minimum total sum of x values across all operations.
    // This is equivalent to finding the minimum total increase applied to all elements such that the final array is non-decreasing.

    // Let the final array be nums'. We require nums'[i] <= nums'[i+1].
    // nums'[i] = nums[i] + Sum(x_k where op_k covers i)
    // The total sum of x's is Sum(x_k over all ops_k).

    // A simpler perspective: we only care about the required increases at each step where the sequence decreases.
    // If nums[i] > nums[i+1], we need to increase nums[i+1] by at least D = nums[i] - nums[i+1] relative to nums[i].
    // Any operation that increases nums[i+1] and *not* nums[i] contributes to fixing this.

    // Crucially, an operation on [l..r] with value x increases *all* elements in that range by x.
    // If we fix the final value of nums'[i] = V_i, then the total increase at i is V_i - nums[i].
    // The total sum of x's is related to how these increases are distributed.

    // Consider the necessary *local* increase at the boundary i to i+1.
    // If nums[i] > nums[i+1], the required increase for nums[i+1] relative to nums[i] is D = nums[i] - nums[i+1].
    // If we perform an operation with value x on [i+1..r], this adds x to nums[i+1] but not to nums[i]. This contributes to fixing the gap.
    // If we perform an operation with value x on [l..i+1], this adds x to both. This doesn't help fix the gap relative to nums[i].

    // It turns out the minimum total sum of x's is simply the sum of all positive differences:
    // Sum(max(0, nums[i] - nums[i+1])) for i = 0 to n-2.

    // Let's verify this hypothesis with the examples.

    // Example 1: nums = [3, 3, 2, 1]
    // i=0: nums[0] - nums[1] = 3 - 3 = 0. max(0, 0) = 0.
    // i=1: nums[1] - nums[2] = 3 - 2 = 1. max(0, 1) = 1.
    // i=2: nums[2] - nums[3] = 2 - 1 = 1. max(0, 1) = 1.
    // Total sum = 0 + 1 + 1 = 2. Matches example output.

    // Example 2: nums = [5, 1, 2, 3]
    // i=0: nums[0] - nums[1] = 5 - 1 = 4. max(0, 4) = 4.
    // i=1: nums[1] - nums[2] = 1 - 2 = -1. max(0, -1) = 0.
    // i=2: nums[2] - nums[3] = 2 - 3 = -1. max(0, -1) = 0.
    // Total sum = 4 + 0 + 0 = 4. Matches example output.

    // The reasoning is related to how the required "height" difference must be covered by operations starting *after* the drop.
    // When nums[i] > nums[i+1], we need nums'[i+1] >= nums'[i].
    // Let the final required increase for nums[i] be I_i = nums'[i] - nums[i].
    // We need nums[i] + I_i <= nums[i+1] + I_{i+1}, or I_{i+1} - I_i >= nums[i] - nums[i+1].
    // If nums[i] - nums[i+1] = D > 0, we need I_{i+1} - I_i >= D.

    // The minimum total sum of x's required is $\sum_{i=0}^{n-2} \max(0, \text{nums}[i] - \text{nums}[i+1])$.

    for (let i = 0; i < n - 1; i++) {
        const difference = nums[i] - nums[i + 1];
        if (difference > 0) {
            totalSumX += difference;
        }
    }

    return totalSumX;
}

